import React from 'react';

export default function AutomataSVG({ automata, type, highlightPath = [] }) {
  if (!automata || !automata.states) {
    return (
      <div style={{ color: '#94a3b8', padding: '20px' }}>
        No automata generated
      </div>
    );
  }

  const states = automata.states;
  const radius = 28;
  const centerX = 300;
  const centerY = 180;
  const circleRadius = 120;

  const positions = {};
  states.forEach((state, i) => {
    const angle = (2 * Math.PI * i) / states.length;

    positions[state] = {
      x: centerX + circleRadius * Math.cos(angle),
      y: centerY + circleRadius * Math.sin(angle),
    };
  });

  const accepts = new Set(
    type === 'nfa'
      ? [automata.accept]
      : automata.accepts || []
  );

  const transitionMap = {};

  Object.entries(automata.transitions || {}).forEach(([from, trans]) => {
    Object.entries(trans).forEach(([symbol, to]) => {
      const destinations = Array.isArray(to) ? to : [to];
      destinations.forEach(dest => {
        const key = `${from}->${dest}`;
        if (!transitionMap[key]) {
          transitionMap[key] = { from, to: dest, symbols: [] };
        }
        if (!transitionMap[key].symbols.includes(symbol)) {
          transitionMap[key].symbols.push(symbol);
        }
      });
    });
  });

  const transitions = Object.values(transitionMap).map(t => ({
    ...t,
    symbol: t.symbols.join(', ')
  }));

  return (
    <svg width="100%" height="400" viewBox="0 0 600 400">
      <defs>
        <marker
          id="arrow"
          markerWidth="8"
          markerHeight="8"
          refX="7"
          refY="4"
          orient="auto"
          markerUnits="strokeWidth"
        >
          <path d="M0,0 L8,4 L0,8 Z" fill="#94a3b8" />
        </marker>
      </defs>

      {transitions.map((t, i) => {
        const from = positions[t.from];
        const to = positions[t.to];

        if (!from || !to) return null;

        const highlighted =
          highlightPath.includes(t.from) &&
          highlightPath.includes(t.to);

        const stroke = highlighted ? '#f59e0b' : '#94a3b8';

        if (t.from === t.to) {
          const loopTop = from.y - radius - 35;
          const path = `M ${from.x - 16} ${from.y - radius + 2} Q ${from.x} ${loopTop - 20} ${from.x + 16} ${from.y - radius + 2}`;

          return (
            <g key={i}>
              <path
                d={path}
                fill="none"
                stroke={stroke}
                strokeWidth="2.5"
                markerEnd="url(#arrow)"
              />
              <text
                x={from.x}
                y={loopTop - 15}
                fill={symbolColor(t.symbol)}
                fontSize="13"
                textAnchor="middle"
              >
                {t.symbol}
              </text>
            </g>
          );
        }

        const dx = to.x - from.x;
        const dy = to.y - from.y;
        const angle = Math.atan2(dy, dx);
        let rot = angle * (180 / Math.PI);
        if (rot > 90 || rot < -90) {
          rot += 180;
        }

        const startX = from.x + radius * Math.cos(angle);
        const startY = from.y + radius * Math.sin(angle);
        const endX = to.x - radius * Math.cos(angle);
        const endY = to.y - radius * Math.sin(angle);

        const reverseExists = transitions.some(
          other => other.from === t.to && other.to === t.from
        );

        const mx = (startX + endX) / 2;
        const my = (startY + endY) / 2;

        if (reverseExists) {
          const curveStrength = 42;
          const nx = -dy;
          const ny = dx;
          const len = Math.sqrt(nx * nx + ny * ny);

          const offsetX = (nx / len) * curveStrength;
          const offsetY = (ny / len) * curveStrength;

          const cx = mx + offsetX;
          const cy = my + offsetY;

          const path = `M ${startX} ${startY} Q ${cx} ${cy} ${endX} ${endY}`;

          const labelOffsetX = (nx / len) * (curveStrength + 15);
          const labelOffsetY = (ny / len) * (curveStrength + 15);

          return (
            <g key={i}>
              <path
                d={path}
                fill="none"
                stroke={stroke}
                strokeWidth="2.5"
                markerEnd="url(#arrow)"
              />
              <text
                transform={`translate(${mx + labelOffsetX}, ${my + labelOffsetY}) rotate(${rot})`}
                fill={symbolColor(t.symbol)}
                fontSize="13"
                textAnchor="middle"
                dominantBaseline="central"
              >
                {t.symbol}
              </text>
            </g>
          );
        }

        const path = `M ${startX} ${startY} L ${endX} ${endY}`;
        const len = Math.sqrt(dx * dx + dy * dy);
        const nx = -dy / len;
        const ny = dx / len;
        const labelX = mx + nx * 12;
        const labelY = my + ny * 12;

        return (
          <g key={i}>
            <path
              d={path}
              fill="none"
              stroke={stroke}
              strokeWidth="2.5"
              markerEnd="url(#arrow)"
            />
            <text
              transform={`translate(${labelX}, ${labelY}) rotate(${rot})`}
              fill={symbolColor(t.symbol)}
              fontSize="13"
              textAnchor="middle"
              dominantBaseline="central"
            >
              {t.symbol}
            </text>
          </g>
        );
      })}

      {states.map(state => {
        const pos = positions[state];
        const highlighted = highlightPath.includes(state);

        return (
          <g key={state}>
            <circle
              cx={pos.x}
              cy={pos.y}
              r={radius}
              fill={highlighted ? 'rgba(245,158,11,0.15)' : '#0f172a'}
              stroke={highlighted ? '#f59e0b' : '#475569'}
              strokeWidth="3"
            />
            <text
              x={pos.x}
              y={pos.y}
              fill="white"
              fontSize="16"
              textAnchor="middle"
              dominantBaseline="central"
              fontWeight="bold"
            >
              {state}
            </text>
            {state === automata.start && (
              <text
                x={pos.x - 14}
                y={pos.y - 10}
                fill="white"
                fontSize="20"
                textAnchor="middle"
                fontWeight="bold"
              >
                -
              </text>
            )}
            {accepts.has(state) && (
              <text
                x={pos.x + 14}
                y={pos.y - 10}
                fill="#34d399"
                fontSize="16"
                textAnchor="middle"
                fontWeight="bold"
              >
                +
              </text>
            )}
          </g>
        );
      })}
    </svg>
  );
}

function symbolColor(symbol) {
  if (symbol.includes('ε')) return '#a78bfa';
  return '#cbd5e1';
}
